import React, { useState, useEffect } from 'react';
import { View, Text, TextInput, Button, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AuthContext = React.createContext();

const AuthProvider = ({ children }) => {
  const [userToken, setUserToken] = useState(null);
  const [userData, setUserData] = useState(null);

  useEffect(() => {
    const loadToken = async () => {
      try {
        const token = await AsyncStorage.getItem('userToken');
        const data = await AsyncStorage.getItem('userData');
        if (token) {
          setUserToken(token);
          setUserData(JSON.parse(data));
        }
      } catch (e) {
        console.error('Failed to load token', e);
      }
    };
    loadToken();
  }, []);

  const signIn = async (username, password) => {
    try {
      // Replace with your authentication logic
      const response = await fakeAuthApi(username, password);
      const { token, user } = response;
      await AsyncStorage.setItem('userToken', token);
      await AsyncStorage.setItem('userData', JSON.stringify(user));
      setUserToken(token);
      setUserData(user);
    } catch (e) {
      Alert.alert('Login failed', e.message);
    }
  };

  const signOut = async () => {
    try {
      await AsyncStorage.removeItem('userToken');
      await AsyncStorage.removeItem('userData');
      setUserToken(null);
      setUserData(null);
    } catch (e) {
      console.error('Failed to sign out', e);
    }
  };

  return (
    <AuthContext.Provider value={{ userToken, userData, signIn, signOut }}>
      {children}
    </AuthContext.Provider>
  );
};

const fakeAuthApi = async (username, password) => {
  // Simulate API call
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (username === 'user' && password === 'pass') {
        resolve({ token: 'fake-token', user: { name: 'John Doe', email: 'john@example.com' } });
      } else {
        reject(new Error('Invalid credentials'));
      }
    }, 1000);
  });
};

const LoginScreen = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const { signIn } = React.useContext(AuthContext);

  return (
    <View>
      <TextInput placeholder="Username" value={username} onChangeText={setUsername} />
      <TextInput placeholder="Password" value={password} onChangeText={setPassword} secureTextEntry />
      <Button title="Sign In" onPress={() => signIn(username, password)} />
    </View>
  );
};

const HomeScreen = () => {
  const { userData, signOut } = React.useContext(AuthContext);

  return (
    <View>
      <Text>Welcome, {userData?.name}</Text>
      <Button title="Sign Out" onPress={signOut} />
    </View>
  );
};

const App = () => {
  const { userToken } = React.useContext(AuthContext);

  return userToken ? <HomeScreen /> : <LoginScreen />;
};

export default () => (
  <AuthProvider>
    <App />
  </AuthProvider>
);